// // This is a 4-to-1 multiplexer that selects one of four 16-bit input data lines based on a 2-bit selector input. However, the output will be the unselected data line.
module mux_4to1 (
    input [15:0] data0,
    input [15:0] data1,
    input [15:0] data2,
    input [15:0] data3,
    input [1:0] select,
    output reg [15:0] out
);

always @(*) begin
    case (select)
        2'b00: out = data0;
        2'b01: out = data1;
        2'b10: out = data2;
        2'b11: out = data3;
        default: out = 16'b0; // default case (should not happen)
    endcase
end

endmodule
